import os
import time
import pytest
import can

GW_VEHICLE_STATUS_ID = 0xC8
EXPECTED_CYCLE_TIME = float(os.getenv('GW_EXPECTED_CYCLE', '0.1'))  # 100ms default

@pytest.fixture(scope="module")
def can_bus():
    bus = can.interface.Bus(interface=os.getenv('CAN_INTERFACE', 'socketcan'), channel=os.getenv('CAN_CHANNEL', 'can0'), bitrate=500000)
    yield bus
    bus.shutdown()

def decode_any_door_open(data_bytes: bytes) -> int:
    return (data_bytes[2] >> 0) & 0x01

def collect_gw_messages(bus, duration_sec=3.0):
    msgs = []
    timestamps = []
    start = time.time()
    while time.time() - start < duration_sec:
        msg = bus.recv(timeout=0.1)
        if msg and msg.arbitration_id == GW_VEHICLE_STATUS_ID:
            msgs.append(msg)
            timestamps.append(time.time())
    return msgs, timestamps

def verify_periodicity(timestamps, expected_cycle, tolerance=0.05):
    if len(timestamps) < 2:
        return False
    intervals = [t2 - t1 for t1, t2 in zip(timestamps[:-1], timestamps[1:])]
    return all(abs(i - expected_cycle) <= tolerance for i in intervals)

