def test_tc_gw_door_per_003_constant_state(can_bus):
    msgs, timestamps = collect_gw_messages(can_bus, 3.0)
    assert len(msgs) > 5
    states = {decode_any_door_open(m.data) for m in msgs}
    assert len(states) == 1
    assert verify_periodicity(timestamps, EXPECTED_CYCLE_TIME)

def test_tc_gw_door_per_005_no_message_loss(can_bus):
    msgs, timestamps = collect_gw_messages(can_bus, 5.0)
    assert len(msgs) > 10
    assert verify_periodicity(timestamps, EXPECTED_CYCLE_TIME)
    for msg in msgs:
        assert decode_any_door_open(msg.data) in (0, 1)
